# ── BUILD EXCEL ──────────────────────────────────────────────────────────────

wb = openpyxl.Workbook()
ws = wb.active
ws.title = "Family Office Intelligence"

HEADER_BG   = "1A1A2E"
ROW_EVEN    = "EFF6FF"
ROW_ODD     = "FFFFFF"

header_font  = Font(name="Arial", bold=True, color="FFFFFF", size=10)
data_font    = Font(name="Arial", size=9)
center_align = Alignment(horizontal="center", vertical="center", wrap_text=True)
left_align   = Alignment(horizontal="left", vertical="top", wrap_text=True)
thin         = Side(style="thin", color="DDDDDD")
thin_border  = Border(left=thin, right=thin, bottom=thin)

for col_idx, col_name in enumerate(columns, 1):
    cell = ws.cell(row=1, column=col_idx, value=col_name)
    cell.font = header_font
    cell.fill = PatternFill("solid", fgColor=HEADER_BG)
    cell.alignment = center_align
    cell.border = thin_border

for row_idx, record in enumerate(records, 2):
    bg = ROW_EVEN if row_idx % 2 == 0 else ROW_ODD
    for col_idx, value in enumerate(record, 1):
        cell = ws.cell(row=row_idx, column=col_idx, value=value)
        cell.font = data_font
        cell.fill = PatternFill("solid", fgColor=bg)
        cell.alignment = left_align
        cell.border = thin_border

col_widths = [32,10,12,20,12,22,28,42,38,28,18,22,20,28,30,14,22,18,16,14,35,26,12,26,20,18,10,12,28,12,38]
for i, w in enumerate(col_widths, 1):
    ws.column_dimensions[get_column_letter(i)].width = w

ws.row_dimensions[1].height = 35
ws.freeze_panes = "A2"
ws.auto_filter.ref = f"A1:{get_column_letter(len(columns))}1"

wb.save("FamilyOffice_Intelligence_Dataset.xlsx")
print(f"Done! {len(records)} records written to FamilyOffice_Intelligence_Dataset.xlsx")